const FRAMEWORKS = {
  'CCSS-M': { name: 'Common Core State Standards for Mathematics', short: 'Common Core (Math)', org: 'CCSSO / NGA' },
  'CCSS-ELA': { name: 'Common Core State Standards for English Language Arts', short: 'Common Core (ELA)', org: 'CCSSO / NGA' },
  'NGSS': { name: 'Next Generation Science Standards', short: 'NGSS', org: 'Achieve / NRC' },
  'ACTFL World-Readiness': { name: 'ACTFL World-Readiness Standards for Learning Languages', short: 'ACTFL', org: 'ACTFL' },
  'AP/Advanced (beyond CCSS)': { name: 'AP & Advanced (beyond Common Core ceiling)', short: 'AP / Advanced', org: 'College Board' }
};

function getStandard(skillId) { return STANDARDS[skillId] || null; }
function frameworkFor(skillId) { const s = STANDARDS[skillId]; return s ? (FRAMEWORKS[s.framework] || null) : null; }

module.exports = { STANDARDS, FRAMEWORKS, getStandard, frameworkFor };
